const contactForm=document.getElementById("contact-form");contactForm&&contactForm.addEventListener("submit",async e=>{e.preventDefault();const t=document.getElementById("response-msg");t.innerText="Envoi en cours...";const n={name:document.getElementById("name").value,email:document.getElementById("email").value,message:document.getElementById("message").value};try{const e=await fetch("https://hugo-contact.mcugnolio-662.workers.dev",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(n)});e.ok?(t.innerHTML="<span style='color: green;'>Message envoyé avec succès !</span>",contactForm.reset()):t.innerHTML="<span style='color: red;'>Erreur lors de l'envoi via le Worker.</span>"}catch{t.innerHTML="<span style='color: red;'>Impossible de joindre le serveur.</span>"}})